const STORAGE_KEY="magalu_system_user",turmaSections=Array.from(document.querySelectorAll("[data-turma]")),logoutButton=document.getElementById("logout-button"),agendaUserName=document.getElementById("agenda-user-name"),agendaUserRole=document.getElementById("agenda-user-role");function redirectToLogin(){window.location.replace(new URL("../",window.location.href))}function normalizeTurma(e){return e?String(e).trim().toUpperCase().replace(/^TURMA\s+/,""):""}function setSectionVisibility(e,a){e.hidden=!a,e.style.display=a?"grid":"none"}function readStoredUser(){const e=localStorage.getItem(STORAGE_KEY);if(!e)return null;try{return JSON.parse(e)}catch(e){return null}}function renderAgendaForTurma(e){const a=normalizeTurma(e);let t=!1;return turmaSections.forEach(e=>{const n=normalizeTurma(e.dataset.turma)===a;setSectionVisibility(e,n),n&&(t=!0)}),a?t?(agendaUserName.textContent=`Agenda liberada para ${e}`,void(agendaUserRole.textContent="A agenda geral aparece para todos, e abaixo voce visualiza apenas os compromissos da sua turma.")):(agendaUserName.textContent="Agenda indisponivel",void(agendaUserRole.textContent=`Nenhuma agenda foi configurada para ${e}.`)):(agendaUserName.textContent="Turma nao encontrada",void(agendaUserRole.textContent="Seu cadastro nao possui turma definida para liberar uma agenda especifica."))}const user=readStoredUser();user?renderAgendaForTurma(user.turma||user.Turma||""):redirectToLogin(),logoutButton.addEventListener("click",()=>{localStorage.removeItem(STORAGE_KEY),redirectToLogin()});